class PluginBase {
  constructor(e = {}) {
    ((this.name = e.name || '未命名插件'),
      (this.version = e.version || '1.0.0'),
      (this.description = e.description || ''),
      (this.isInitialized = !1),
      (this._state = 'created'));
  }
  init() {
    try {
      return (
        this.log('初始化插件...'),
        this.onInit(),
        (this.isInitialized = !0),
        (this._state = 'initialized'),
        this.log('插件初始化完成'),
        { success: !0 }
      );
    } catch (e) {
      return (this.log(`插件初始化失败: ${e.message}`, 'error'), { success: !1, error: e.message });
    }
  }
  execute(e = {}) {
    if (!this.isInitialized) {
      return { success: !1, error: '插件未初始化' };
    }
    try {
      this.log(`执行操作: ${e.action}`);
      const s = this.onExecute(e);
      return (this.log(`操作完成: ${e.action}`), { success: !0, data: s });
    } catch (s) {
      return (this.log(`操作失败: ${e.action} - ${s.message}`, 'error'), { success: !1, error: s.message });
    }
  }
  destroy() {
    try {
      return (
        this.log('销毁插件...'),
        this.onDestroy(),
        (this.isInitialized = !1),
        (this._state = 'destroyed'),
        this.log('插件销毁完成'),
        { success: !0 }
      );
    } catch (e) {
      return (this.log(`插件销毁失败: ${e.message}`, 'error'), { success: !1, error: e.message });
    }
  }
  log(e, s = 'info') {
    const r = new Date().toLocaleTimeString('zh-CN', { hour12: !1 }),
      t = `[${this.name}]`;
    switch (s) {
      case 'error':
        console.error(`%c${r} ${t} ${e}`, 'color: #dc3545');
        break;
      case 'warning':
        console.warn(`%c${r} ${t} ${e}`, 'color: #ffc107');
        break;
      case 'debug':
        console.debug(`%c${r} ${t} ${e}`, 'color: #6c757d');
        break;
      default:
        console.log(`%c${r} ${t} ${e}`, 'color: #007bff');
    }
  }
  validateParams(e, s = []) {
    for (const r of s) {
      if (void 0 === e[r] || null === e[r]) {
        throw new Error(`缺少必需参数: ${r}`);
      }
    }
  }
  onInit() {
    throw new Error('子类必须实现 onInit() 方法');
  }
  onExecute(e = {}) {
    throw new Error('子类必须实现 onExecute() 方法');
  }
  onDestroy() {
    throw new Error('子类必须实现 onDestroy() 方法');
  }
}
window.PluginBase = PluginBase;
